aia() { printf %b "\n\n\e[A >_< "; [ "$1" ] && prompt="$*" || read -re "prompt"; out="${HOME}/logs/ai/$(printf %b "${prompt//[\ ,\\?\-\[\]\'\"\&\#\:\;\*\<\>\(\)\/\´\`\!\{\}\\]/}").md"; printf %b "${prompt}" | tee "${out}" && printf %b "$(curl -sL "https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent" -H 'Content-Type: application/json' -H "X-goog-api-key: ${GOOGLE_API_KEY}" -X POST -d '{"contents": [ {"parts": [ {"text": "'"${prompt}"'" } ] } ] }' | grep --color=never '"text": ' )" | sed -e "/\"text\":\ ./d"  -e "s/\"\,$/\n/" | tee -a "${out}" | bat -pflmd; };
